import{_ as t,c as i,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Command Reference: Slash Commands Quick Reference | Superpowers Tutorial","description":"Learn Superpowers slash commands. This reference details /brainstorm, /write-plan, /execute-plan commands with trigger conditions, use cases, execution steps, and best practices, helping you quickly invoke core workflows, follow TDD principles and systematic debugging, improve code quality and development efficiency, reduce debugging time and error rate, and accelerate iteration speed and delivery frequency.","frontmatter":{"title":"Command Reference: Slash Commands Quick Reference | Superpowers Tutorial","sidebarTitle":"Commands Quick Reference","subtitle":"Command Reference: Slash Commands Quick Reference","description":"Learn Superpowers slash commands. This reference details /brainstorm, /write-plan, /execute-plan commands with trigger conditions, use cases, execution steps, and best practices, helping you quickly invoke core workflows, follow TDD principles and systematic debugging, improve code quality and development efficiency, reduce debugging time and error rate, and accelerate iteration speed and delivery frequency.","tags":["Commands","Reference","Slash Commands"],"prerequisite":[],"order":270},"headers":[],"relativePath":"obra/superpowers/appendix/commands-reference/index.md","filePath":"obra/superpowers/appendix/commands-reference/index.md"}'),n={name:"obra/superpowers/appendix/commands-reference/index.md"};function s(r,e,l,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="command-reference-slash-commands-quick-reference" tabindex="-1">Command Reference: Slash Commands Quick Reference <a class="header-anchor" href="#command-reference-slash-commands-quick-reference" aria-label="Permalink to &quot;Command Reference: Slash Commands Quick Reference&quot;">​</a></h1><p>Superpowers provides three slash commands for quickly invoking core workflow skills.</p><h2 id="command-overview" tabindex="-1">Command Overview <a class="header-anchor" href="#command-overview" aria-label="Permalink to &quot;Command Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th><th>Calls Skill</th><th>Use Case</th></tr></thead><tbody><tr><td><code>/brainstorm</code></td><td>Creative design requirement clarification</td><td>brainstorming</td><td>Before creative work</td></tr><tr><td><code>/write-plan</code></td><td>Write detailed implementation plan</td><td>writing-plans</td><td>Before multi-step tasks with specs/requirements</td></tr><tr><td><code>/execute-plan</code></td><td>Batch execute plan tasks</td><td>executing-plans</td><td>When executing an existing plan</td></tr></tbody></table><hr><h2 id="brainstorm" tabindex="-1">/brainstorm <a class="header-anchor" href="#brainstorm" aria-label="Permalink to &quot;/brainstorm&quot;">​</a></h2><p><strong>Description</strong>: Clarify requirements and explore creative ideas before design</p><p><strong>Trigger Conditions</strong>:</p><ul><li>Create new feature</li><li>Build new component</li><li>Add new functionality</li><li>Modify existing behavior</li></ul><p><strong>Calls Skill</strong>: <code>superpowers:brainstorming</code></p><p><strong>Usage Example</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/brainstorm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Add user profile editing feature&quot;</span></span></code></pre></div><p><strong>Core Process</strong>:</p><ol><li>Understand project context</li><li>Ask clarification questions one at a time</li><li>Present design proposal (in 200-300 word segments)</li><li>Save design document to <code>docs/plans/</code></li><li>Commit design to version control</li></ol><p><strong>Important Notes</strong>:</p><ul><li>Must be executed before writing code</li><li>Ask only one question at a time</li><li>Design document must be committed</li></ul><hr><h2 id="write-plan" tabindex="-1">/write-plan <a class="header-anchor" href="#write-plan" aria-label="Permalink to &quot;/write-plan&quot;">​</a></h2><p><strong>Description</strong>: Break down requirements into executable small tasks</p><p><strong>Trigger Conditions</strong>:</p><ul><li>Clear requirements or specifications exist</li><li>Tasks require multi-step implementation</li><li>Need detailed implementation plan</li></ul><p><strong>Calls Skill</strong>: <code>superpowers:writing-plans</code></p><p><strong>Usage Example</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/write-plan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;docs/plans/2024-02-01-user-profile-design.md&quot;</span></span></code></pre></div><p><strong>Core Process</strong>:</p><ol><li>Read design document or requirement specifications</li><li>Break down into 2-5 minute tasks</li><li>Write complete code for each task</li><li>Include testing steps</li><li>Save implementation plan</li></ol><p><strong>Task Breakdown Principles</strong>:</p><ul><li>Each task completable in 2-5 minutes</li><li>Task granularity small enough for &quot;no-context&quot; engineers to execute</li><li>Each task includes implementation and verification</li></ul><p><strong>Important Notes</strong>:</p><ul><li>Tasks must be sufficiently small</li><li>Each task must have acceptance criteria</li><li>Plan document should be clear and readable</li></ul><hr><h2 id="execute-plan" tabindex="-1">/execute-plan <a class="header-anchor" href="#execute-plan" aria-label="Permalink to &quot;/execute-plan&quot;">​</a></h2><p><strong>Description</strong>: Batch execute tasks from a plan with review checkpoints</p><p><strong>Trigger Conditions</strong>:</p><ul><li>Implementation plan is already written</li><li>Need to batch execute tasks</li><li>Execute in separate session (recommended)</li></ul><p><strong>Calls Skill</strong>: <code>superpowers:executing-plans</code></p><p><strong>Usage Example</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/execute-plan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;docs/plans/2024-02-01-user-profile-implementation.md&quot;</span></span></code></pre></div><p><strong>Core Process</strong>:</p><ol><li>Read implementation plan</li><li>Execute tasks one by one</li><li>Run tests after each task</li><li>Set review checkpoints after each batch</li><li>Verify after completing all tasks</li></ol><p><strong>Execution Strategy</strong>:</p><ul><li>Execute tasks in order</li><li>Verify tests after each task</li><li>Conduct code review after each batch (typically 3-5 tasks)</li><li>Stop and debug on failure</li></ul><p><strong>Important Notes</strong>:</p><ul><li>Suitable for execution in separate sessions</li><li>Difference from subagent-driven-development is in execution approach</li><li>Must follow TDD principles</li></ul><hr><h2 id="command-usage-recommendations" tabindex="-1">Command Usage Recommendations <a class="header-anchor" href="#command-usage-recommendations" aria-label="Permalink to &quot;Command Usage Recommendations&quot;">​</a></h2><h3 id="when-to-use-commands" tabindex="-1">When to Use Commands <a class="header-anchor" href="#when-to-use-commands" aria-label="Permalink to &quot;When to Use Commands&quot;">​</a></h3><p><strong>Use commands when</strong>:</p><ul><li>You know exactly which workflow you need</li><li>Want to quickly start a standard process</li><li>Using Claude Code</li></ul><p><strong>Use skills directly when</strong>:</p><ul><li>Unsure which skill is needed</li><li>AI proactively suggests using a skill</li><li>Calling through Skill tool</li></ul><h3 id="commands-vs-skills" tabindex="-1">Commands vs Skills <a class="header-anchor" href="#commands-vs-skills" aria-label="Permalink to &quot;Commands vs Skills&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Slash Commands</th><th>Skill Calls</th></tr></thead><tbody><tr><td>Invocation Method</td><td>User actively inputs <code>/command</code></td><td>AI auto-invokes or through Skill tool</td></tr><tr><td>Use Case</td><td>You know which process is needed</td><td>Let AI recommend appropriate process</td></tr><tr><td>Platform Support</td><td>Claude Code</td><td>Claude Code, OpenCode, Codex</td></tr></tbody></table><h3 id="typical-workflows" tabindex="-1">Typical Workflows <a class="header-anchor" href="#typical-workflows" aria-label="Permalink to &quot;Typical Workflows&quot;">​</a></h3><p><strong>Complete Development Process</strong>:</p><ol><li><code>/brainstorm</code> - Design requirements</li><li><code>/write-plan</code> - Write plan</li><li><code>/execute-plan</code> - Execute implementation</li></ol><p><strong>Bug Fix Process</strong>:</p><ul><li>Use <code>systematic-debugging</code> skill directly</li></ul><p><strong>Quick Prototype Process</strong>:</p><ul><li><code>/brainstorm</code> - Quick design</li><li>Implement directly (skip detailed planning)</li></ul><hr><h2 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h2><p>This chapter introduced three slash commands provided by Superpowers:</p><ul><li><code>/brainstorm</code>: Creative design requirement clarification</li><li><code>/write-plan</code>: Write detailed implementation plan</li><li><code>/execute-plan</code>: Batch execute plan tasks</li></ul><p>These commands provide convenient access to core workflows in Claude Code, suitable for scenarios where you know which process you need.</p><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../agents-reference/">Agent Reference</a></strong>.</p><p>You&#39;ll learn:</p><blockquote><ul><li>Concepts and purposes of the agent system</li><li>Detailed explanation of code-reviewer agent</li><li>How to define and use custom agents</li></ul></blockquote></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>Command</th><th>File Path</th><th>Line</th></tr></thead><tbody><tr><td>/brainstorm command definition</td><td><a href="https://github.com/obra/superpowers/blob/main/commands/brainstorm.md" target="_blank" rel="noreferrer"><code>commands/brainstorm.md</code></a></td><td>1-7</td></tr><tr><td>/write-plan command definition</td><td><a href="https://github.com/obra/superpowers/blob/main/commands/write-plan.md" target="_blank" rel="noreferrer"><code>commands/write-plan.md</code></a></td><td>1-7</td></tr><tr><td>/execute-plan command definition</td><td><a href="https://github.com/obra/superpowers/blob/main/commands/execute-plan.md" target="_blank" rel="noreferrer"><code>commands/execute-plan.md</code></a></td><td>1-7</td></tr></tbody></table><p><strong>Key Features</strong>:</p><ul><li><code>disable-model-invocation: true</code>: Prevents direct model invocation, ensuring execution through the skill system</li><li>Command files only contain instruction calls; actual logic is in corresponding skills</li></ul><p><strong>Invocation Chain</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Slash command → Skill system (Skill tool) → Corresponding skill (SKILL.md) → Execute workflow</span></span></code></pre></div></details>',70)])])}const h=t(n,[["render",s]]);export{u as __pageData,h as default};
